import React from "react";
import "../App.css";
import { useNavigate } from "react-router-dom";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faRightToBracket } from "@fortawesome/free-solid-svg-icons";

export default function LandingPage() {
  const router = useNavigate();

  return (
    <div className="landingPageContainer">
      <nav>
        <div className="navHeader">
          <img src="/video_full_logo.gif" alt="" />
        </div>
        <div className="navList">
          <p
            onClick={() => {
              router("/ash");
            }}
          >
            Join as Guest
          </p>
          <p
            onClick={() => {
              router("/auth");
            }}
          >
            Register
          </p>
          <div
            onClick={() => {
              router("/auth");
            }}
            role="button"
          >
            {/* <p>Login</p> */}

            <a
              class="icon-link icon-link-hover"
              style="--bs-icon-link-transform: translate3d(0, -.125rem, 0);"
              href="#"
            >
              <svg
                xmlns="http://www.w3.org/2000/svg"
                class="bi"
                viewBox="0 0 16 16"
                aria-hidden="true"
              >
                <path d="M4 1.5H3a2 2 0 0 0-2 2V14a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V3.5a2 2 0 0 0-2-2h-1v1h1a1 1 0 0 1 1 1V14a1 1 0 0 1-1 1H3a1 1 0 0 1-1-1V3.5a1 1 0 0 1 1-1h1v-1z" />
                <path d="M9.5 1a.5.5 0 0 1 .5.5v1a.5.5 0 0 1-.5.5h-3a.5.5 0 0 1-.5-.5v-1a.5.5 0 0 1 .5-.5h3zm-3-1A1.5 1.5 0 0 0 5 1.5v1A1.5 1.5 0 0 0 6.5 4h3A1.5 1.5 0 0 0 11 2.5v-1A1.5 1.5 0 0 0 9.5 0h-3z" />
              </svg>
              Icon link
            </a>
          </div>
        </div>
      </nav>

      <div className="landingMainContainer">
        <div>
          <h1>
            <span style={{ color: "#D97500" }}>Connect</span> with your{" "}
            <span style={{ color: "#ed2424" }}>Loved</span> ones
          </h1>

          <p>Cover the distance by A_Call</p>
          <div
            style={{ cursor: "pointer" }}
            onClick={() => router("/auth")}
            role="button"
            tabIndex={0}
            onKeyPress={(e) => {
              if (e.key === "Enter" || e.key === " ") router("/auth");
            }}
          >
            Get Started
          </div>
        </div>

        <div>{/* <img src="/mobile.png" alt="" /> */}</div>
      </div>
    </div>
  );
}
